import React, { useEffect, useState } from 'react';

const models = [
  { name: 'llama-3.3-70b (Groq)', color: '#f97316' },
  { name: 'gemini-2.0-flash', color: '#2563eb' },
  { name: 'mistral-7b (Ollama)', color: '#7c3aed' },
];

const AILoadingState: React.FC = () => {
  const [dots, setDots] = useState('');
  const [elapsed, setElapsed] = useState(0);

  useEffect(() => {
    // Animate dots
    const dotsInterval = setInterval(() => {
      setDots(prev => prev.length >= 3 ? '' : prev + '.');
    }, 400);

    // Count elapsed seconds
    const timeInterval = setInterval(() => {
      setElapsed(prev => prev + 1);
    }, 1000);

    return () => {
      clearInterval(dotsInterval);
      clearInterval(timeInterval);
    };
  }, []);

  return (
    <div style={{
      background: 'white',
      border: '1px solid #e2e8f0',
      borderRadius: '12px',
      padding: '2rem',
      marginTop: '1rem'
    }}>
      {/* Header */}
      <div style={{
        display: 'flex',
        justifyContent: 'space-between',
        alignItems: 'center',
        marginBottom: '1.5rem'
      }}>
        <p style={{ fontWeight: 700, color: '#1e293b', margin: 0 }}>
          Querying AI models{dots}
        </p>
        <span style={{
          color: '#94a3b8',
          fontSize: '0.85rem',
          fontFamily: 'monospace'
        }}>
          {elapsed}s elapsed
        </span>
      </div>

      {/* Model cards */}
      {models.map((model) => (
        <div key={model.name} style={{
          display: 'flex',
          alignItems: 'center',
          gap: '1rem',
          padding: '0.85rem 1rem',
          borderRadius: '8px',
          background: '#f8fafc',
          marginBottom: '0.75rem',
          border: '1px solid #e2e8f0'
        }}>
          {/* Pulsing dot */}
          <div style={{
            width: '10px',
            height: '10px',
            borderRadius: '50%',
            background: model.color,
            animation: 'pulse 1.2s ease-in-out infinite',
            flexShrink: 0
          }} />

          <span style={{
            fontSize: '0.9rem',
            fontWeight: 600,
            color: '#334155',
            flex: 1
          }}>
            {model.name}
          </span>

          {/* Shimmer bar */}
          <div style={{
            height: '8px',
            width: '120px',
            borderRadius: '999px',
            background: 'linear-gradient(90deg, #e2e8f0 25%, #cbd5e1 50%, #e2e8f0 75%)',
            backgroundSize: '200% 100%',
            animation: 'shimmer 1.5s infinite'
          }} />

          <span style={{
            fontSize: '0.8rem',
            color: model.color,
            fontWeight: 600,
            minWidth: '70px',
            textAlign: 'right'
          }}>
            thinking...
          </span>
        </div>
      ))}

      <p style={{
        color: '#94a3b8',
        fontSize: '0.8rem',
        marginTop: '1rem',
        marginBottom: 0,
        textAlign: 'center'
      }}>
        All 3 models are running in parallel
      </p>

      <style>{`
        @keyframes pulse {
          0%, 100% { opacity: 1; transform: scale(1); }
          50% { opacity: 0.4; transform: scale(0.85); }
        }
        @keyframes shimmer {
          0% { background-position: 200% 0; }
          100% { background-position: -200% 0; }
        }
      `}</style>
    </div>
  );
};

export default AILoadingState;
